import re

from .generic import apply_rules

# https://en.wiktionary.org/wiki/Category:Latvian_suffixes

DEFAULT_RULES = {
    # feminine nouns
    re.compile(r"(?:훮ju|훮jas|훮jai|훮jam|훮j훮s)$"): "훮ja",
    re.compile(r"(?:휆ju|휆jas|휆jai|휆jam|휆j훮s)$"): "휆ja",
    re.compile(r"(?:ieci|ieces|iecei|iec휆|ie훾u|iec휆m|iec휆s)$"): "iece",
    re.compile(r"(?:ieti|ietes|ietei|iet휆|ietes|ie큄u|iet휆m|iet휆s)$"): "iete",
    re.compile(r"(?:iju|ijas|ijai|ijam)$"): "ija",
    re.compile(r"(?:카bu|카bas|카bai|카b훮m|카b훮s)$"): "카ba",
    re.compile(r"(?:카gu|카ga|카gam|카gi|카gus|카giem|카gos|카gas|카gai|카g훮|카g훮m|카g훮s)$"): "카gs",
    re.compile(r"(?:카va|카vu|카vam|카vas|카vai|카vus|카viem|카vos|카v훮|카v훮m|카v훮s)$"): "카vs",
    re.compile(r"(?:큄anu|큄anas|큄anai|큄an훮|큄an훮m|큄an훮s)$"): "큄ana",
    re.compile(r"(?:umu|uma|umam|um훮|um훮m|um훮s)$"): "ums",  # |um
    # masculine nouns
    re.compile(r"(?:훮ju|훮ja|훮jam|훮j|훮ji|훮jus|훮jiem|훮jos)$"): "훮js",
    re.compile(r"(?:i흨u|i흨a|i흨am|i흨|i흨i|i흨us|i흨iem|i흨os)$"): "i흨큄",
    re.compile(
        r"(?:isku|iska|iskam|isk훮|iski|iskus|iskiem|isko|iskos|iskai|iskas|isk훮m|isk훮s)$"
    ): "isks",
    re.compile(r"(?:ismu|isma|ismam|ism훮|iski|ism)$"): "isms",
    re.compile(r"(?:카ti|카큄a|카tim|카t카|카t|카큄i|카큄us|카큄u|카큄iem|카큄os)$"): "카tis",
    re.compile(r"(?:kli|k캬a|klim|kl카|k캬i|k캬us|k캬iem|k캬os)$"): "klis",
    re.compile(r"(?:nieku|nieka|niekam|niek훮|nieki|niekus|niekiem|niekos)$"): "nieks",
    re.compile(r"(?:ni|흨a|nim|n카|흨i|흨us|흨u|흨iem|흨os)$"): "nis",
    # fallback
    re.compile(r"(?:as|ai|훮|훮m|훮s)$"): "a",
    re.compile(r"(?:ei|es|휆|휆m|휆s)$"): "e",
    re.compile(r"(?:is|im|카|iem|카s)$"): "is",
    # re.compile(r"(?:os|us)$"): "s",
    # re.compile(r"(?:휆to|휆ts)$"): "휆t",
}


def apply_lv(token: str) -> str | None:
    "Apply pre-defined rules for Latvian."
    if len(token) < 5:
        return None

    return apply_rules(token, DEFAULT_RULES)
